-- BUILDERS (11 services)
-- ==========================================================

-- 1. Builders x Web Design
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'builders',
  'web-design',
  'A builder''s website needs to do one thing above all else: prove that you can deliver quality work. Homeowners commissioning extensions, loft conversions, and new builds are making decisions worth tens or hundreds of thousands of pounds, and they need visual proof that you are capable, reliable, and professional before they will even pick up the phone. This means your website must be built around project galleries with high-quality before-and-after photography, detailed case studies showing the scope and quality of completed work, and social proof from verified homeowners who trusted you with their property. Unlike service businesses that sell appointments, building companies sell outcomes, and your website must showcase those outcomes prominently. We build construction and building company websites designed for mobile-first browsing because your potential clients are searching on their phones, often while standing on site. Every page is structured to move visitors from admiration of your work to a quote request, with clear calls to action, an easy-to-use enquiry form that captures project details, and trust signals including insurance details, trade body memberships, and federation logos.',
  'Over seventy percent of homeowners now research builders online before requesting a quote, even when they have been personally recommended. They want to see completed projects, read reviews, and verify credentials before making contact. A builder without a professional website, or worse, with a dated site featuring low-quality images and broken pages, immediately loses credibility. Your website is the difference between being shortlisted and being ignored.',
  'We design builder websites mobile-first because tradespeople and their clients both browse predominantly on phones. Project galleries use lazy-loading high-resolution images with before-and-after sliders. We build quote request forms that capture project type, property details, and timeline to give your team qualified leads rather than vague enquiries.',
  '[{"title": "No project gallery to showcase completed work", "description": "Homeowners spending fifty thousand pounds on an extension need to see evidence of similar completed projects. Builders without a professional gallery of their work force prospects to rely entirely on verbal descriptions and a handful of Facebook photos. Competitors with well-presented portfolios win the shortlist before you even get a chance to quote."}, {"title": "Website not usable on mobile devices", "description": "Site workers, project managers, and homeowners all browse on mobile phones. A builder''s website that is difficult to navigate on a small screen, with images that take too long to load and text too small to read, loses visitors within seconds. Most building company websites were built for desktop and have never been properly adapted for mobile browsing."}, {"title": "No way for prospects to request a quote easily", "description": "Many builder websites offer only a phone number or a basic contact form that tells you nothing about the project. Without a structured enquiry form that captures project type, property details, budget range, and timeline, your team wastes time on calls that could have been pre-qualified. Prospects who cannot easily submit an enquiry move to the next search result."}]',
  '[{"title": "Project gallery with before-and-after showcases", "description": "We build stunning project galleries with high-resolution photography, before-and-after image sliders, and detailed case study pages for your best work. Each project page includes the scope, duration, challenges overcome, and client testimonials. This visual proof is the single most powerful conversion tool for any building company website."}, {"title": "Mobile-first design for on-site browsing", "description": "Every builder website we create is designed mobile-first. Images are optimised for fast loading on 4G connections, navigation works perfectly with thumb-based scrolling, and click-to-call buttons are prominent on every page. Whether a homeowner is browsing at home or a project manager is checking your site between tasks, the experience is seamless."}, {"title": "Structured quote request forms that pre-qualify leads", "description": "Our enquiry forms capture the information your team needs to provide an accurate initial response: project type, property type, approximate budget, desired timeline, and postcode. This pre-qualification means fewer wasted site visits, more relevant quotes, and higher conversion rates from enquiry to signed contract."}]',
  '[{"question": "How do we get good photos of our building projects for the website?", "answer": "We provide a photography brief and can arrange professional shoots of your current and completed projects. If professional photography is not in budget initially, we provide detailed guidance on taking effective project photos with a smartphone, including lighting tips, angles that showcase scale and quality, and how to capture before-and-after comparisons effectively."}, {"question": "Will the website work for both residential and commercial building services?", "answer": "Yes. We structure builder websites with clear separation between residential and commercial services, each with their own project galleries, testimonials, and enquiry paths. A homeowner looking for a kitchen extension and a business needing commercial fit-out have different needs, and the website guides each to the relevant content and contact method."}, {"question": "How long does a builder''s website take to build?", "answer": "Most building company websites launch within four to six weeks. The timeline depends partly on how many project case studies we include at launch, as these require photography, content writing, and client testimonial collection. We can launch with a core set of projects and add more over time as new work is completed."}, {"question": "Can clients leave reviews directly on the website?", "answer": "We integrate Google review feeds and can embed reviews from Checkatrade, TrustATrader, or other platforms your company uses. We also build a testimonial submission system where satisfied clients can provide feedback that, with your approval, appears on relevant project pages. This keeps fresh social proof flowing without requiring manual updates."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 2. Builders x SEO
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'builders',
  'seo',
  'When a homeowner types builder near me or extension builder Kent into Google, the companies appearing in the top three map pack results and the first page of organic results receive the vast majority of enquiries. For building companies, every first-page ranking position represents a direct pipeline of high-value project leads worth tens of thousands of pounds each. The challenge is that construction is one of the most locally competitive search verticals, with hundreds of building firms, national lead generation platforms like MyBuilder and Bark, and directory sites all fighting for the same keywords. A builder without a deliberate SEO strategy is invisible to the thousands of homeowners actively searching for construction services each month in their area. We build SEO campaigns specifically for building companies, targeting the high-intent search terms that lead to quoted projects rather than tyre-kickers, optimising Google Business Profiles for map pack dominance, and creating service-area content that captures searches across every town and village your team operates in.',
  'Referrals and word of mouth remain important for builders, but they are not scalable and not predictable. The firms growing fastest are those supplementing referrals with consistent organic search visibility. Every search for loft conversion near me or new build contractor represents a homeowner ready to get quotes. If your company does not appear, that project goes to a competitor. SEO provides a reliable, compounding source of project enquiries that grows in value over time.',
  'Builder SEO demands a service-plus-location matrix approach. We create optimised pages for each service type, such as extensions, loft conversions, new builds, and renovations, crossed with every geographic area you serve. Google Business Profile optimisation focuses on construction-specific categories and a review strategy targeting completed project clients.',
  '[{"title": "Invisible for high-value construction search terms", "description": "Keywords like extension builder, loft conversion company, and new build contractor carry enormous commercial value, with each enquiry potentially worth tens of thousands in project revenue. Most building companies have no dedicated pages targeting these specific searches, losing high-value leads to competitors and national platforms that have invested in search visibility."}, {"title": "MyBuilder, Bark, and Checkatrade outranking your own website", "description": "Lead generation platforms invest millions in SEO to rank above individual building companies. They then charge you per lead for enquiries that should have come directly through your own website. Without a strategy to compete with these platforms in search results, you remain dependent on third parties who take a cut of every project."}, {"title": "No geographic coverage across your actual service area", "description": "Your building company may serve a twenty-mile radius, but your website only mentions your base town. Homeowners in surrounding villages and towns searching for a local builder will never find you because Google has no content connecting your services to their location. Every unserved area is a territory of lost opportunities."}]',
  '[{"title": "Service-specific landing pages targeting high-value keywords", "description": "We create dedicated, optimised pages for every construction service you offer: house extensions, loft conversions, new builds, garage conversions, renovations, and groundworks. Each page targets the specific search terms homeowners use, includes relevant project photography, and is structured to convert visitors into quote requests for that specific service type."}, {"title": "Geographic coverage pages across your full service area", "description": "We build location-specific pages for every town and area your company serves, creating a matrix of service-plus-location content. Builder in Maidstone, loft conversion Canterbury, extension specialist Ashford: each combination gets a dedicated, locally relevant page that captures search traffic across your entire operating radius."}, {"title": "Google Business Profile optimisation for the construction map pack", "description": "We optimise your Google Business Profile with precise construction service categories, professional project photos, and a structured review generation programme targeting recently completed projects. Building companies we manage consistently dominate the map pack for their primary service and location keywords."}]',
  '[{"question": "How competitive is SEO for builders compared to other trades?", "answer": "Construction SEO is highly competitive because the value per lead is so high. A single extension or loft conversion project can be worth thirty to sixty thousand pounds, which means ranking positions are extremely valuable. However, most individual builders have not invested in SEO, so the competition is primarily from platforms like MyBuilder and Checkatrade rather than other local firms, creating significant opportunity for those who invest."}, {"question": "How long before SEO brings in new project enquiries?", "answer": "Most building companies see ranking improvements for specific service-plus-location terms within eight to twelve weeks. Broader competitive terms like builder plus county typically take four to six months. We focus initial efforts on the highest-value, most achievable keywords to generate returns as quickly as possible while building toward more competitive positions."}, {"question": "Can SEO help me stop paying for leads on MyBuilder and Bark?", "answer": "That is one of the primary goals. As your organic search visibility increases, you receive more direct enquiries through your own website where you pay nothing per lead. Many of our building clients significantly reduce or eliminate their platform spending within six to twelve months of starting SEO, redirecting that budget toward organic visibility that compounds over time."}, {"question": "Should I target residential and commercial building keywords separately?", "answer": "Absolutely. Homeowners searching for an extension builder and businesses searching for commercial contractors use completely different terms and have different expectations. We build separate keyword strategies and landing pages for each market, ensuring your content speaks directly to the intent behind each search type."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
