-- 3. Builders x Lead Capture
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'builders',
  'lead-capture',
  'Building companies invest significantly in generating website traffic through SEO, directory listings, and word of mouth, but most convert a tiny fraction of visitors into actual quote requests. A homeowner lands on your site, browses your project gallery, perhaps reads a testimonial, and then leaves to continue comparing builders without making contact. They may visit five or six building company websites in a single research session, and without a mechanism to capture their details during that process, you have no way to follow up. The homeowner forgets your company name, returns to Google, and contacts whichever builder they remember or find first. We build lead capture systems designed for the construction buying cycle, which typically involves weeks of research before a homeowner commits to getting quotes. From project planning guides that exchange value for an email address, to instant quote estimator tools that engage visitors and capture project details, to automated follow-up sequences that keep your company front of mind during the research phase, every element is designed to turn website browsers into booked site visits.',
  'The average homeowner visits multiple builder websites before requesting quotes. Without lead capture, you are relying entirely on being memorable enough to receive a callback from someone who saw six similar websites. A lead capture system transforms anonymous browsers into identified prospects you can follow up with, nurture over time, and convert when they are ready to proceed with their project.',
  'Construction lead capture must reflect the high-value, research-intensive nature of building projects. We create tools that help prospects plan their project, such as extension cost calculators, planning permission guides, and project timeline tools, in exchange for contact details. Follow-up sequences are timed to the typical construction decision cycle.',
  '[{"title": "Website visitors browse project galleries then disappear", "description": "Homeowners researching builders spend time looking at your completed projects and reading testimonials but leave without making contact because they are not ready to commit to a quote request yet. Without capturing their details during this research phase, every one of these interested prospects is lost to you permanently."}, {"title": "Only capturing prospects ready for a site visit today", "description": "Your quote request form only works for homeowners who have already decided to get quotes. The much larger group still researching, comparing options, or working out their budget have no way to engage with your company at a lower commitment level. These early-stage researchers represent your future projects, and you are losing them all."}, {"title": "No follow-up system for enquiries that go quiet", "description": "Many homeowners request a quote, receive your estimate, and then go quiet for weeks or months while they consider their options, arrange finances, or wait for planning permission. Without an automated follow-up system, these warm leads go cold. Your team forgets to chase, the homeowner engages another builder, and the time invested in the site visit and quote is wasted."}]',
  '[{"title": "Project planning tools that capture prospect details", "description": "We build interactive tools like extension cost estimators, renovation budget planners, and project timeline calculators that provide genuine value to homeowners while capturing their contact details and project information. A homeowner who has used your cost estimator and received a personalised budget range is significantly more likely to request a formal quote from your company."}, {"title": "Downloadable guides for homeowners at the research stage", "description": "We create valuable resources like The Complete Guide to Planning Your Home Extension, What to Expect During a Loft Conversion, and Understanding Planning Permission in Kent. These guides address the exact questions homeowners have during the early research phase, capturing their email address in exchange for genuinely useful information."}, {"title": "Automated nurture sequences for the construction buying cycle", "description": "We design email sequences that keep your building company front of mind during the weeks or months between initial research and quote requests. Content includes project planning tips, examples of completed work similar to their planned project, and seasonal reminders about optimal build timing. Each email reinforces your expertise and nudges the prospect toward booking a site visit."}]',
  '[{"question": "What kind of lead magnets work best for building companies?", "answer": "Interactive tools consistently outperform static content for builders. Cost estimators, project timeline planners, and budget calculators engage homeowners actively and capture detailed project information alongside contact details. Downloadable guides on topics like planning permission processes and choosing the right builder also perform well for prospects at the early research stage."}, {"question": "How do you follow up with leads without being pushy?", "answer": "Our follow-up sequences provide value rather than pressure. Each email shares useful project planning advice, showcases relevant completed projects, or offers seasonal guidance about build timing. The tone is helpful and expert rather than salesy. Homeowners appreciate receiving useful information and remember your company when they are ready to proceed."}, {"question": "Can lead capture replace paying for leads on MyBuilder or Checkatrade?", "answer": "Lead capture generates enquiries from your own website traffic at no per-lead cost. As your organic traffic grows through SEO, the volume of captured leads increases without additional spending. Many building companies we work with gradually reduce platform spending as their own lead generation improves, keeping more profit from each project."}, {"question": "How does lead capture work with our existing quoting process?", "answer": "Captured leads integrate with your existing workflow. When a prospect is ready for a quote, they are flagged for your estimating team with full project details already captured. For prospects still in the research phase, automated sequences handle the nurturing until they are ready. Your team only spends time on leads that are qualified and actively seeking quotes."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
