-- 6. Builders x Social Media Setup
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'builders',
  'social-media-setup',
  'Social media is one of the most powerful marketing tools available to building companies, yet most builders either ignore it completely or use it inconsistently. The reason social media works so well for builders is simple: construction is inherently visual, and people love watching buildings go up. Time-lapse videos of extensions, before-and-after transformation posts, and progress photos from active sites generate the kind of organic engagement that other industries can only dream of. A single well-photographed kitchen extension can generate dozens of enquiries when shared on the right platforms. Yet most building companies have a Facebook page that was last updated six months ago, no Instagram presence despite running a visual business, and a Google Business Profile with two reviews from three years ago. We set up and optimise building company social media profiles to showcase your work effectively, build a portfolio that generates enquiries, and establish a review presence that gives homeowners the confidence to choose you over competitors.',
  'Homeowners choosing a builder check social media as part of their research. They want to see recent projects, read reviews, and get a sense of your team and working style. A dormant or unprofessional social media presence suggests a company that is either too small to care or too disorganised to maintain it. An active, well-presented social presence with recent project content and strong reviews provides the social proof that tips undecided prospects toward choosing your firm.',
  'Builder social media setup focuses on the platforms that generate construction enquiries: Facebook for local community visibility, Instagram for visual project showcasing, and Google Business Profile for review credibility. We configure each profile with professional branding, optimised descriptions, and a content framework built around site progress updates that require nothing more than a daily smartphone photo.',
  '[{"title": "Incredible project work with zero online visibility", "description": "Your team completes stunning transformations every month, extensions that double living space, loft conversions that add entire floors, and renovations that bring properties back to life. Yet none of this work is visible online because nobody takes photos, and when they do, the images sit on a phone and are never shared. Your best marketing asset is going completely to waste."}, {"title": "No Google reviews despite dozens of satisfied clients", "description": "Homeowners who had excellent experiences with your building company have never been asked to leave a review. Meanwhile, competitors with proactive review strategies display twenty or thirty five-star Google reviews. When a prospect is comparing two builders with similar portfolios, the one with significantly more positive reviews wins the enquiry every time."}, {"title": "Inconsistent social profiles creating poor first impression", "description": "Your Facebook page uses your old logo, your Google Business Profile has the wrong phone number, and you have no Instagram account despite being in one of the most visual industries possible. When a referred prospect checks your social media and finds incomplete, outdated profiles, it directly contradicts the recommendation they received."}]',
  '[{"title": "Visual-first social profiles showcasing your best work", "description": "We set up Instagram and Facebook profiles designed to showcase construction projects effectively. Profile images, cover photos, and descriptions are professionally branded. We configure project highlight categories on Instagram for extensions, loft conversions, new builds, and other service types so prospects can quickly find work relevant to their planned project."}, {"title": "Google review generation system for completed projects", "description": "We implement a structured review request process that makes it easy for satisfied clients to leave Google reviews at the right moment, typically just after project completion when satisfaction is highest. We set up the request templates, timing, and follow-up reminders so your team can generate reviews consistently without any administrative burden."}, {"title": "Daily site content framework requiring minimal effort", "description": "We create a simple content framework where taking a single smartphone photo on site each day, with basic guidance on what to capture, feeds into scheduled social media posts. Progress photos, before-and-after comparisons, and team-on-site images are templated and scheduled, maintaining an active presence with less than five minutes of daily effort from your site team."}]',
  '[{"question": "Which social media platforms matter most for builders?", "answer": "Facebook and Instagram are the primary platforms for residential builders. Facebook provides local community visibility and is where homeowners ask for builder recommendations in local groups. Instagram is ideal for showcasing project photography and before-and-after transformations. Google Business Profile is essential for review credibility. For commercial builders, LinkedIn becomes important for connecting with architects, developers, and facilities managers."}, {"question": "We do not have time to post on social media every day from site", "answer": "Our system is designed to take less than five minutes per day. Take one photo on your phone at the end of each day. Our content framework turns that single image into branded posts scheduled across your platforms. You do not need to write captions, choose hashtags, or sit at a computer. One photo and the system handles the rest."}, {"question": "How do we get clients to leave Google reviews?", "answer": "We set up an automated review request system that sends a personalised message to clients at the point of project completion, with a direct link to your Google review page. The message is timed for when satisfaction is highest and makes leaving a review as easy as clicking a link and typing a few sentences. Most clients are happy to help when asked at the right moment."}, {"question": "Can social media actually generate building project enquiries?", "answer": "Yes. Building companies with active social profiles showing recent completed projects consistently report receiving direct enquiries through social media. A before-and-after kitchen extension post can generate multiple enquiries from homeowners planning similar projects. The visual nature of construction makes social media unusually effective compared to other service industries."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
